create table dirkspzm32.bde_fa_auftrag (
    sid                         varchar2(2 char) default '01' not null enable,
    firma_nr                    number(2, 0) default 1 not null enable,
    abnr                        varchar2(20 char),
    leitzahl                    number(*, 0) not null enable,
    fa_ag                       number(*, 0) not null enable,
    fa_upos                     number(*, 0) not null enable,
    satzart                     varchar2(2 char),
    res_id                      number(*, 0),
    anz_res                     number(*, 0),
    ab_artikel_id               number(*, 0),
    ab_soll_mg                  number(*, 3),
    ab_ist_mg                   number(*, 3),
    ab_text1                    varchar2(255 char),
    ab_text2                    varchar2(255 char),
    ab_text3                    varchar2(255 char),
    ab_ende_status              varchar2(3 char),
    ag_soll_mg                  number(*, 3),
    ag_ist_mg                   number(*, 3),
    ag_ist_mg_b                 number(*, 3),
    ag_ist_mg_schrott           number(*, 3),
    ag_ist_mg_ruesten           number(*, 3),
    ruest_zeit_gepl             number(*, 12),
    ruest_zeit_ist              number(*, 12),
    prod_zeit_gepl              number(*, 12),
    prod_zeit_ist               number(*, 12),
    stoer_zeit_gepl             number(*, 12),
    stoer_zeit_ist              number(*, 12),
    zeit_einheit                number(*, 12),
    termin_start_gepl           date,
    termin_ende_gepl            date,
    termin_start_ist            date,
    termin_ende_ist             date,
    freig_status                varchar2(3 char) default 'N',
    freig_wer                   number(*, 0),
    freig_wann                  date,
    status_res_id               number(*, 0),
    status_id                   number(*, 0),
    status_begin                date,
    kunden_nr                   varchar2(20 char),
    ag_artikel_id               number(*, 0),
    kd_art_nr                   varchar2(30 char),
    ag_bez1                     varchar2(255 char),
    ag_bez2                     varchar2(255 char),
    ag_text1                    varchar2(255 char),
    ag_text2                    varchar2(255 char),
    ag_text3                    varchar2(255 char),
    zeichnung                   varchar2(255 char),
    schrott_proz                number(*, 6),
    nutzen                      number(*, 6),
    gewicht                     number(*, 6),
    schrott                     number(*, 6),
    verbrauch                   number(*, 6),
    einsatz                     number(*, 6),
    max_takt_ausf_zeit          number(*, 12),
    min_takt_zeit               number(*, 12),
    max_takt_zeit               number(*, 12),
    status_freigabe             number(*, 0),
    ag_id                       varchar2(20 char),
    charge_id                   number(*, 0),
    kenz_letzt_ag               number(1, 0),
    zeichnung_index             varchar2(10 char),
    lhm_name                    varchar2(50 char),
    lhm_menge                   number(*, 3),
    lte_name                    varchar2(22 char),
    lte_menge                   number(*, 3),
    best_nr_kunde               varchar2(30 char),
    kenz_lhm_druck              varchar2(1 char),
    mde_ist_mg                  number(*, 3),
    mde_ist_mg_b                number(*, 3),
    mde_ist_mg_schrott          number(*, 3),
    mde_ist_mg_ruesten          number(*, 3),
    mde_micro_stop              number(*, 0),
    mde_ist_mg_t                number(*, 3),
    mde_ist_mg_b_t              number(*, 3),
    mde_ist_mg_schrott_t        number(*, 3),
    mde_ist_mg_ruesten_t        number(*, 3),
    mde_micro_stop_t            number(*, 0),
    lte_lhm_lagen               number(2, 0),
    lte_lhm_pro_lage            number(2, 0),
    lte_anz                     number(*, 3),
    lte_anz_ist                 number(*, 3),
    lhm_anz                     number(*, 3),
    lhm_anz_ist                 number(*, 3),
    abfuell_abschalt_grob       number(*, 6),
    abfuell_abschalt_mittel     number(*, 6),
    abfuell_abschalt_fein       number(*, 6),
    abfuell_toleranz_plus       number(*, 6),
    abfuell_toleranz_minus      number(*, 6),
    abfuell_silo                varchar2(30 char),
    abfuell_soll                number(*, 3),
    prod_params                 varchar2(4000 char),
    nio_res_id                  number(*, 0),
    quitt_gruppe_ag             number(*, 0),
    prod_menge_p_einheit        number(*, 3) default 1,
    prod_menge_p_einheit_op     varchar2(10 char) default 'MUL',
    kunden_nr_adr_liefer        varchar2(20 char),
    ag_los_mg                   number(*, 3),
    rcv_ag_ist_mg               number(*, 3),
    rcv_ag_ist_mg_b             number(*, 3),
    rcv_ag_ist_mg_schrott       number(*, 3),
    rcv_ag_ist_mg_ruesten       number(*, 3),
    rcv_ruest_zeit_ist          number(*, 12),
    rcv_prod_zeit_ist           number(*, 12),
    rcv_stoer_zeit_ist          number(*, 12),
    ag_los_ist_mg               number(*, 3),
    packschema_kopf_id          varchar2(20 char),
    ag_art_laenge               number(*, 3),
    ag_art_breite               number(*, 3),
    ag_art_dicke                number(*, 3),
    ag_art_durch                number(*, 3),
    kunden_ab                   varchar2(20 char),
    kunden_ab_pos               varchar2(20 char),
    kunden_ab_upos              varchar2(20 char),
    term_wunsch                 date,
    term_best                   date,
    transp_zeit                 number(*, 12),
    anz_rohstoffe               number(*, 3),
    ausgef_ende                 varchar2(1 char),
    ag_prod_frei                varchar2(1 char),
    ag_ueberlappen              number(12, 3),
    ag_opt_grp                  varchar2(50 char),
    prioritaet                  varchar2(20 char),
    vorgangsqualifikation       varchar2(50 char),
    anz_mitarbeiter             number(*, 3),
    lueckenfueller              varchar2(1 char),
    termin_start_frueh          date,
    start_batch_by_order_start  varchar2(200 char),
    ext_arbeits_anweisung       varchar2(200 char),
    job_sequenz                 number(*, 0),
    kunden_ab_text              varchar2(255 char),
    ruest_zeit_erf              number(*, 12),
    prod_zeit_erf               number(*, 12),
    stoer_zeit_erf              number(*, 12),
    termin_start_erf            date,
    termin_ende_erf             date,
    kategorie                   varchar2(20 char),
    auf_id                      number(*, 0),
    ma_reserviert               varchar2(1 char),
    ma_res_menge                number(*, 3),
    ma_res_charge_id            number(*, 0),
    ma_hersteller_kuerzel_liste varchar2(100 char),
    ma_res_menge_komm           number(*, 3),
    adress_id                   number(*, 0),
    lohn_arbeit                 varchar2(1 char) default 'F',
    created_date                date default sysdate not null enable,
    created_login_id            number(*, 0) default - 1 not null enable,
    last_change_date            date,
    last_change_login_id        number(*, 0),
    rcv_ruest_zeit_erf          number(*, 12),
    rcv_prod_zeit_erf           number(*, 12),
    seq_nr                      number,
    lead_leitzahl               number,
    primaer_leitzahl            number,
    nr_pruefung                 varchar2(20 char),
    fremd_zeichnung             varchar2(30 char),
    zeichnungname               varchar2(255 char)
);

alter table dirkspzm32.bde_fa_auftrag
    add constraint bde_fa_auftrag_freig_status
        check ( freig_status in ( 'N', 'A', 'AP', 'AR', 'TF',
                                  'F', 'XF' ) ) enable;

alter table dirkspzm32.bde_fa_auftrag
    add constraint ix_bde_fa_auftrag_auf_id
        unique ( auf_id,
                 sid,
                 firma_nr )
            using index enable;

alter table dirkspzm32.bde_fa_auftrag
    add constraint pk_bde_fa_auftrag
        primary key ( leitzahl,
                      fa_ag,
                      fa_upos )
            using index enable;


